{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 smoke 테스트가 통과될 경우 금요일 15:00 KST로 한다.",
        "conditions": ["smoke 테스트 통과"],
        "rejected_or_superseded": "수요일 릴리스 제안은 최종 결정이 아니며 내부 stretch goal로만 남았다."
      },
      {
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인한다.",
        "conditions": ["packageName mismatch 발생 시"],
        "followup_boundary": "contract 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "proposed_by": "Hara",
        "outcome": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "proposed_by": "Seoyeon",
        "status": "내부 stretch goal이며 최종 릴리스 결정 아님"
      },
      {
        "goal": "README install steps를 목요일까지 검토",
        "status": "가능하면 진행하자는 제안이며 owner는 배정되지 않음"
      }
    ],
    "non_decisions": [
      {
        "item": "최종 릴리스 승인 권한자",
        "status": "결정되지 않음"
      },
      {
        "item": "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부",
        "status": "결정되지 않음"
      },
      {
        "item": "고객 또는 외부 파트너",
        "status": "언급되지 않음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball path가 릴리스를 지연시킬 수 있음",
        "status": "확인된 리스크"
      },
      {
        "risk": "README install steps가 오래되었으면 릴리스 노트가 사용자를 오도할 수 있음",
        "status": "확인된 리스크"
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "명시적으로 확인됨"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 failure triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "명시적으로 확인됨"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 게시한 뒤 generated tarball path를 확인한다.",
      "due": "정확한 deadline 없음",
      "status": "confirmed",
      "source_certainty": "명시적으로 확인됨"
    },
    {
      "owner": null,
      "task": "README install steps를 목요일까지 가능하면 검토한다.",
      "due": "목요일 if possible",
      "status": "unassigned_proposed_followup",
      "source_certainty": "owner 미배정, 확정 action으로 취급 금지"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST smoke test 결과를 확인한다.",
      "smoke 통과 여부에 따라 금요일 15:00 KST 공개 릴리스 목표 유지 여부를 판단한다.",
      "Doyun의 action_items.md failure triage note 작성 여부를 확인한다.",
      "Minjun 결과 게시 후 Hara의 generated tarball path 확인 결과를 확인한다.",
      "README install steps 검토 owner를 지정할지 결정한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너명",
      "예산 관련 사실",
      "보안 사고",
      "production outage",
      "법무 승인 필요 여부",
      "명시되지 않은 owner",
      "명시되지 않은 deadline"
    ]
  },
  "non_invention_rules": {
    "customer": "고객 또는 외부 파트너는 언급되지 않았으므로 생성하지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "outage": "production outage는 언급되지 않았으므로 생성하지 않는다.",
    "legal": "법무 승인 요구사항은 언급되지 않았으므로 생성하지 않는다.",
    "owner": "owner가 명시되지 않은 항목에는 owner를 배정하지 않는다.",
    "deadline": "deadline이 명시되지 않은 항목에는 정확한 deadline을 만들지 않는다.",
    "release_condition": "금요일 15:00 KST 공개 릴리스는 smoke 통과 조건부 목표로만 기록한다."
  }
}
